import React, {
  useState,
  useRef,
  useCallback,
  useEffect,
  createContext,
  useContext,
} from 'react';

// ─── GLOBAL CONFIRM DIALOG CONTEXT ───────────────────────────────────────────
const ConfirmContext = createContext(null);
function useConfirm() {
  return useContext(ConfirmContext);
}

function ConfirmProvider({ children }) {
  const [dialog, setDialog] = useState(null);
  const [suppress, setSuppress] = useState(() => {
    try {
      return load('suppressConfirm2', {});
    } catch {
      return {};
    }
  });

  const confirm = useCallback(
    (opts) => {
      // opts: { key, title, msg, confirmLabel, danger }
      const key = opts.key || 'default';
      if (suppress[key]) {
        opts.onOk && opts.onOk();
        return;
      }
      setDialog({ ...opts, key });
    },
    [suppress]
  );

  const handleOk = () => {
    dialog?.onOk && dialog.onOk();
    setDialog(null);
  };
  const handleCancel = () => {
    dialog?.onCancel && dialog.onCancel();
    setDialog(null);
  };
  const toggleSuppress = (checked) => {
    const ns = checked
      ? { ...suppress, [dialog.key]: true }
      : (() => {
          const n = { ...suppress };
          delete n[dialog.key];
          return n;
        })();
    setSuppress(ns);
    save('suppressConfirm2', ns);
  };

  return (
    <ConfirmContext.Provider value={confirm}>
      {children}
      {dialog && (
        <div
          onClick={handleCancel}
          style={{
            position: 'fixed',
            inset: 0,
            background: 'rgba(0,0,0,0.45)',
            zIndex: 99999,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            padding: 20,
            backdropFilter: 'blur(2px)',
          }}
        >
          <div
            onClick={(e) => e.stopPropagation()}
            style={{
              background: '#fff',
              borderRadius: 20,
              padding: '28px 28px 22px',
              width: 380,
              maxWidth: '92vw',
              boxShadow:
                '0 24px 64px rgba(0,0,0,0.22), 0 2px 8px rgba(0,0,0,0.1)',
              border: '1px solid #f1f5f9',
            }}
          >
            {/* Icon + Title */}
            <div
              style={{
                display: 'flex',
                alignItems: 'center',
                gap: 12,
                marginBottom: 10,
              }}
            >
              <div
                style={{
                  width: 40,
                  height: 40,
                  borderRadius: 12,
                  background: dialog.danger === false ? '#fef3c7' : '#fee2e2',
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  flexShrink: 0,
                }}
              >
                {dialog.icon === 'trash' ||
                (!dialog.icon && dialog.danger !== false) ? (
                  <svg
                    width="20"
                    height="20"
                    viewBox="0 0 24 24"
                    fill="none"
                    stroke="#e84040"
                    strokeWidth="2"
                    strokeLinecap="round"
                    strokeLinejoin="round"
                  >
                    <path d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16" />
                  </svg>
                ) : (
                  <svg
                    width="20"
                    height="20"
                    viewBox="0 0 24 24"
                    fill="none"
                    stroke="#d97706"
                    strokeWidth="2"
                    strokeLinecap="round"
                    strokeLinejoin="round"
                  >
                    <path d="M12 9v4m0 4h.01M10.29 3.86L1.82 18a2 2 0 001.71 3h16.94a2 2 0 001.71-3L13.71 3.86a2 2 0 00-3.42 0z" />
                  </svg>
                )}
              </div>
              <div
                style={{
                  fontSize: 16,
                  fontWeight: 800,
                  color: '#0f172a',
                  letterSpacing: -0.3,
                }}
              >
                {dialog.title || 'Confirm'}
              </div>
            </div>
            {/* Message */}
            <div
              style={{
                fontSize: 13,
                color: '#64748b',
                marginBottom: 20,
                lineHeight: 1.65,
                paddingLeft: 52,
              }}
            >
              {dialog.msg}
            </div>
            {/* Suppress checkbox */}
            <div
              style={{
                display: 'flex',
                alignItems: 'center',
                gap: 8,
                marginBottom: 18,
                paddingLeft: 52,
              }}
            >
              <input
                type="checkbox"
                id="gc-suppress"
                style={{
                  accentColor: '#e84040',
                  width: 14,
                  height: 14,
                  cursor: 'pointer',
                }}
                onChange={(e) => toggleSuppress(e.target.checked)}
              />
              <label
                htmlFor="gc-suppress"
                style={{
                  fontSize: 12,
                  color: '#94a3b8',
                  cursor: 'pointer',
                  userSelect: 'none',
                }}
              >
                Don't ask again for this action
              </label>
            </div>
            {/* Buttons */}
            <div style={{ display: 'flex', gap: 10 }}>
              <button
                onClick={handleOk}
                style={{
                  flex: 1,
                  padding: '12px 0',
                  border: 'none',
                  borderRadius: 11,
                  background: dialog.danger === false ? '#f59e0b' : '#e84040',
                  color: '#fff',
                  cursor: 'pointer',
                  fontSize: 13,
                  fontWeight: 800,
                  letterSpacing: 0.1,
                  transition: 'opacity 0.15s',
                }}
                onMouseEnter={(e) => (e.currentTarget.style.opacity = '0.88')}
                onMouseLeave={(e) => (e.currentTarget.style.opacity = '1')}
              >
                {dialog.confirmLabel || 'Yes, Delete'}
              </button>
              <button
                onClick={handleCancel}
                style={{
                  flex: 1,
                  padding: '12px 0',
                  border: '1px solid #e2e8f0',
                  borderRadius: 11,
                  background: '#f8fafc',
                  color: '#374151',
                  cursor: 'pointer',
                  fontSize: 13,
                  fontWeight: 700,
                  transition: 'background 0.15s',
                }}
                onMouseEnter={(e) =>
                  (e.currentTarget.style.background = '#f1f5f9')
                }
                onMouseLeave={(e) =>
                  (e.currentTarget.style.background = '#f8fafc')
                }
              >
                Cancel
              </button>
            </div>
          </div>
        </div>
      )}
    </ConfirmContext.Provider>
  );
}

const Icon = ({
  d,
  size = 16,
  stroke = 'currentColor',
  fill = 'none',
  strokeWidth = 1.8,
}) => (
  <svg
    width={size}
    height={size}
    viewBox="0 0 24 24"
    fill="none"
    stroke={stroke}
    strokeWidth={strokeWidth}
    strokeLinecap="round"
    strokeLinejoin="round"
  >
    {Array.isArray(d) ? (
      d.map((p, i) => <path key={i} d={p} fill={fill} />)
    ) : (
      <path d={d} fill={fill} />
    )}
  </svg>
);

