// ─── MINI CALENDAR ────────────────────────────────────────────────────────────
function MiniCalendar({ t }) {
  const [date, setDate] = useState(new Date());
  const today = new Date();
  const y = date.getFullYear(),
    m = date.getMonth();
  const firstDay = new Date(y, m, 1).getDay();
  const dim = new Date(y, m + 1, 0).getDate();
  const MONTHS = [
    'Jan',
    'Feb',
    'Mar',
    'Apr',
    'May',
    'Jun',
    'Jul',
    'Aug',
    'Sep',
    'Oct',
    'Nov',
    'Dec',
  ];
  const DAYS = ['S', 'M', 'T', 'W', 'T', 'F', 'S'];
  const cells = [
    ...Array(firstDay).fill(null),
    ...Array.from({ length: dim }, (_, i) => i + 1),
  ];
  return (
    <div
      style={{ padding: '12px 14px 16px', borderTop: `1px solid ${t.border}` }}
    >
      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          marginBottom: 10,
        }}
      >
        <button
          onClick={() => setDate(new Date(y, m - 1))}
          style={{
            background: 'none',
            border: 'none',
            cursor: 'pointer',
            color: t.textMuted,
            padding: '2px 6px',
            fontSize: 15,
            lineHeight: 1,
          }}
        >
          ‹
        </button>
        <span style={{ fontSize: 11, fontWeight: 700, color: t.text }}>
          {MONTHS[m]} {y}
        </span>
        <button
          onClick={() => setDate(new Date(y, m + 1))}
          style={{
            background: 'none',
            border: 'none',
            cursor: 'pointer',
            color: t.textMuted,
            padding: '2px 6px',
            fontSize: 15,
            lineHeight: 1,
          }}
        >
          ›
        </button>
      </div>
      <div
        style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(7,1fr)',
          gap: 2,
        }}
      >
        {DAYS.map((d, i) => (
          <div
            key={i}
            style={{
              textAlign: 'center',
              fontSize: 9,
              fontWeight: 800,
              color: t.textLight,
              paddingBottom: 3,
              letterSpacing: 0.5,
            }}
          >
            {d}
          </div>
        ))}
        {cells.map((d, i) => {
          const isToday =
            d &&
            d === today.getDate() &&
            m === today.getMonth() &&
            y === today.getFullYear();
          return (
            <div
              key={i}
              style={{
                textAlign: 'center',
                fontSize: 10,
                padding: '3px 0',
                borderRadius: 5,
                color: isToday ? '#fff' : d ? t.text : 'transparent',
                background: isToday ? t.accent : 'transparent',
                fontWeight: isToday ? 800 : 400,
                cursor: d ? 'pointer' : 'default',
              }}
            >
              {d || ''}
            </div>
          );
        })}
      </div>
    </div>
  );
}

