// Widget sizes defined in WidgetBoard

// Individual widget content renderers
function WidgetTodo({ t, color, notes: _, activateApp }) {
  const [todoLists] = useState(() => load('todoLists', []));
  const allTasks = todoLists.flatMap((l) => l.items || []);
  const done = allTasks.filter((i) => i.done).length;
  const total = allTasks.length;
  const pct = total ? Math.round((done / total) * 100) : 0;
  const pending = allTasks.filter((i) => !i.done).slice(0, 5);
  return (
    <>
      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          marginBottom: 12,
        }}
      >
        <div>
          <div style={{ fontWeight: 900, fontSize: 28, color, lineHeight: 1 }}>
            {pct}%
          </div>
          <div style={{ fontSize: 11, color: t.textMuted }}>
            {done}/{total} tasks done
          </div>
        </div>
        <div
          style={{
            width: 52,
            height: 52,
            borderRadius: '50%',
            border: `4px solid ${t.surface}`,
            background: `conic-gradient(${color} ${pct * 3.6}deg, ${
              t.surface
            } 0deg)`,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
          }}
        >
          <div
            style={{
              width: 36,
              height: 36,
              borderRadius: '50%',
              background: t.card,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
            }}
          >
            <Icon d={Icons.check} size={16} stroke={color} strokeWidth={2.5} />
          </div>
        </div>
      </div>
      <div
        style={{
          height: 8,
          borderRadius: 99,
          background: t.surface,
          overflow: 'hidden',
          marginBottom: 14,
        }}
      >
        <div
          style={{
            height: '100%',
            width: `${pct}%`,
            background: color,
            borderRadius: 99,
            transition: 'width 0.5s',
          }}
        />
      </div>
      {todoLists.slice(0, 3).map((l) => {
        const lPct = l.items?.length
          ? Math.round(
              (l.items.filter((i) => i.done).length / l.items.length) * 100
            )
          : 0;
        return (
          <div key={l.id} style={{ marginBottom: 6 }}>
            <div
              style={{
                display: 'flex',
                justifyContent: 'space-between',
                marginBottom: 2,
              }}
            >
              <span
                style={{
                  fontSize: 11,
                  color: t.text,
                  fontWeight: 600,
                  overflow: 'hidden',
                  textOverflow: 'ellipsis',
                  whiteSpace: 'nowrap',
                  maxWidth: '70%',
                }}
              >
                {l.name}
              </span>
              <span style={{ fontSize: 11, color: t.textMuted }}>{lPct}%</span>
            </div>
            <div
              style={{
                height: 4,
                borderRadius: 99,
                background: t.surface,
                overflow: 'hidden',
              }}
            >
              <div
                style={{
                  height: '100%',
                  width: `${lPct}%`,
                  background: l.color || color,
                  borderRadius: 99,
                }}
              />
            </div>
          </div>
        );
      })}
      {pending.length > 0 && (
        <div
          style={{
            marginTop: 10,
            borderTop: `1px solid ${t.border}`,
            paddingTop: 10,
          }}
        >
          {pending.map((task, i) => (
            <div
              key={i}
              style={{
                fontSize: 12,
                color: t.text,
                padding: '3px 0',
                overflow: 'hidden',
                textOverflow: 'ellipsis',
                whiteSpace: 'nowrap',
              }}
            >
              · {task.text}
            </div>
          ))}
        </div>
      )}
    </>
  );
}

