function WidgetCalendar({ t, color, activateApp }) {
  const [cur, setCur] = useState(new Date());
  const [reminders] = useState(() => load('userReminders', []));
  const DAYS = ['S', 'M', 'T', 'W', 'T', 'F', 'S'];
  const MONTHS = [
    'Jan',
    'Feb',
    'Mar',
    'Apr',
    'May',
    'Jun',
    'Jul',
    'Aug',
    'Sep',
    'Oct',
    'Nov',
    'Dec',
  ];
  const today = new Date();
  const y = cur.getFullYear(),
    m = cur.getMonth();
  const first = new Date(y, m, 1).getDay();
  const dim = new Date(y, m + 1, 0).getDate();
  const cells = [
    ...Array(first).fill(null),
    ...Array.from({ length: dim }, (_, i) => i + 1),
  ];
  const evtsOn = (d) =>
    reminders.filter((r) => {
      if (!r.datetime || r.done) return false;
      const rd = new Date(r.datetime);
      return (
        rd.getFullYear() === y && rd.getMonth() === m && rd.getDate() === d
      );
    });
  const upcoming = reminders
    .filter(
      (r) =>
        r.datetime &&
        !r.done &&
        new Date(r.datetime) >= new Date(today.toDateString())
    )
    .sort((a, b) => new Date(a.datetime) - new Date(b.datetime))
    .slice(0, 3);
  return (
    <>
      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'space-between',
          marginBottom: 8,
        }}
      >
        <button
          onClick={() => setCur(new Date(y, m - 1))}
          style={{
            background: 'none',
            border: 'none',
            cursor: 'pointer',
            color: t.textMuted,
            fontSize: 16,
            lineHeight: 1,
            padding: '0 4px',
          }}
        >
          ‹
        </button>
        <span style={{ fontSize: 14, fontWeight: 800, color: t.text }}>
          {MONTHS[m]} {y}
        </span>
        <button
          onClick={() => setCur(new Date(y, m + 1))}
          style={{
            background: 'none',
            border: 'none',
            cursor: 'pointer',
            color: t.textMuted,
            fontSize: 16,
            lineHeight: 1,
            padding: '0 4px',
          }}
        >
          ›
        </button>
      </div>
      <div
        style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(7,1fr)',
          gap: 1,
          marginBottom: 10,
        }}
      >
        {DAYS.map((d, i) => (
          <div
            key={i}
            style={{
              textAlign: 'center',
              fontSize: 11,
              fontWeight: 800,
              color: t.textLight,
              paddingBottom: 3,
            }}
          >
            {d}
          </div>
        ))}
        {cells.map((d, i) => {
          const isToday =
            d &&
            d === today.getDate() &&
            m === today.getMonth() &&
            y === today.getFullYear();
          const evts = d ? evtsOn(d) : [];
          return (
            <div
              key={i}
              onClick={() => d && activateApp('calendar')}
              style={{
                textAlign: 'center',
                padding: '3px 1px',
                borderRadius: 5,
                cursor: d ? 'pointer' : 'default',
                background: isToday ? color : 'none',
                position: 'relative',
              }}
              onMouseEnter={(e) => {
                if (d && !isToday)
                  e.currentTarget.style.background = t.surfaceHover;
              }}
              onMouseLeave={(e) => {
                if (d && !isToday) e.currentTarget.style.background = 'none';
              }}
            >
              <div
                style={{
                  fontSize: 12,
                  fontWeight: isToday ? 800 : 400,
                  color: isToday ? '#fff' : d ? t.text : 'transparent',
                }}
              >
                {d || ''}
              </div>
              {evts.length > 0 && (
                <div
                  style={{
                    position: 'absolute',
                    bottom: 1,
                    left: '50%',
                    transform: 'translateX(-50%)',
                    width: 3,
                    height: 3,
                    borderRadius: '50%',
                    background: isToday ? '#fff' : color,
                  }}
                />
              )}
            </div>
          );
        })}
      </div>
      {upcoming.length > 0 && (
        <div style={{ borderTop: `1px solid ${t.border}`, paddingTop: 8 }}>
          {upcoming.map((r) => (
            <div
              key={r.id}
              style={{
                display: 'flex',
                gap: 6,
                alignItems: 'center',
                padding: '4px 0',
              }}
            >
              <div
                style={{
                  width: 3,
                  height: 24,
                  borderRadius: 2,
                  background: r.color || color,
                  flexShrink: 0,
                }}
              />
              <div style={{ flex: 1, minWidth: 0 }}>
                <div
                  style={{
                    fontSize: 11,
                    fontWeight: 700,
                    color: t.text,
                    overflow: 'hidden',
                    textOverflow: 'ellipsis',
                    whiteSpace: 'nowrap',
                  }}
                >
                  {r.title}
                </div>
                <div style={{ fontSize: 10, color: t.textMuted }}>
                  {new Date(r.datetime).toLocaleDateString('en-US', {
                    month: 'short',
                    day: 'numeric',
                  })}
                </div>
              </div>
            </div>
          ))}
        </div>
      )}
    </>
  );
}

