function WidgetCalculator({ t, color }) {
  const [display, setDisplay] = useState('0');
  const [expr, setExpr] = useState('');
  const safeMath = (e) => {
    const s = e
      .replace(/×/g, '*')
      .replace(/÷/g, '/')
      .replace(/[^0-9+\-*/.()]/g, '');
    // eslint-disable-next-line no-new-func
    return Function('"use strict";return (' + s + ')')();
  };
  const press = (val) => {
    if (display === 'Error') {
      setDisplay('0');
      setExpr('');
    }
    if (val === 'C') {
      setDisplay('0');
      setExpr('');
      return;
    }
    if (val === '⌫') {
      setDisplay((d) => (d.length > 1 ? d.slice(0, -1) : '0'));
      return;
    }
    if (val === '+/-') {
      setDisplay((d) => (d.startsWith('-') ? d.slice(1) : '-' + d));
      return;
    }
    if (val === '%') {
      setDisplay((d) => String(parseFloat(d) / 100));
      return;
    }
    if (val === '=') {
      try {
        const res = safeMath(expr + display);
        if (!isFinite(res)) {
          setDisplay('Error');
          setExpr('');
          return;
        }
        setDisplay(String(parseFloat(res.toPrecision(12))));
        setExpr('');
      } catch {
        setDisplay('Error');
        setExpr('');
      }
      return;
    }
    if (['+', '-', '×', '÷'].includes(val)) {
      setExpr(expr + display + val);
      setDisplay('0');
      return;
    }
    if (val === '.') {
      if (display.includes('.')) return;
      setDisplay((d) => d + '.');
      return;
    }
    setDisplay((d) => (d === '0' ? val : d + val));
  };
  const rows = [
    ['C', '⌫', '%', '÷'],
    ['7', '8', '9', '×'],
    ['4', '5', '6', '-'],
    ['1', '2', '3', '+'],
    ['+/-', '0', '.', '='],
  ];
  const isOp = (v) => ['+', '-', '×', '÷', '='].includes(v);
  const isFn = (v) => ['C', '⌫', '%'].includes(v);
  return (
    <div style={{ display: 'flex', flexDirection: 'column', height: '100%' }}>
      <div
        style={{
          padding: '8px 4px 6px',
          borderRadius: 10,
          background: 'rgba(0,0,0,0.08)',
          marginBottom: 8,
        }}
      >
        <div
          style={{
            fontSize: 10,
            color: t.textMuted,
            textAlign: 'right',
            minHeight: 14,
            paddingRight: 4,
          }}
        >
          {expr || ' '}
        </div>
        <div
          style={{
            fontSize: 28,
            fontWeight: 700,
            color: t.text,
            textAlign: 'right',
            paddingRight: 4,
            letterSpacing: -0.5,
            overflow: 'hidden',
            textOverflow: 'ellipsis',
            whiteSpace: 'nowrap',
          }}
        >
          {display}
        </div>
      </div>
      <div
        style={{ display: 'flex', flexDirection: 'column', gap: 4, flex: 1 }}
      >
        {rows.map((row, ri) => (
          <div
            key={ri}
            style={{
              display: 'grid',
              gridTemplateColumns: 'repeat(4,1fr)',
              gap: 4,
              flex: 1,
            }}
          >
            {row.map((val) => (
              <button
                key={val}
                onClick={() => press(val)}
                style={{
                  border: 'none',
                  borderRadius: 8,
                  cursor: 'pointer',
                  fontSize: 13,
                  fontWeight: 700,
                  background:
                    val === '='
                      ? color
                      : isOp(val)
                      ? color + '22'
                      : isFn(val)
                      ? 'rgba(0,0,0,0.1)'
                      : 'rgba(0,0,0,0.06)',
                  color: val === '=' ? '#fff' : isOp(val) ? color : t.text,
                  transition: 'opacity 0.1s',
                }}
                onMouseDown={(e) => (e.currentTarget.style.opacity = '0.7')}
                onMouseUp={(e) => (e.currentTarget.style.opacity = '1')}
                onMouseLeave={(e) => (e.currentTarget.style.opacity = '1')}
              >
                {val}
              </button>
            ))}
          </div>
        ))}
      </div>
    </div>
  );
}

function WidgetHabits({ t, color, activateApp }) {
  const [habits] = useState(() => load('habits', []));
  const today = todayStr();
  const last7 = getLast7();
  const done = habits.filter((h) => h.completions?.[today]).length;
  const total = habits.length;
  const pct = total ? Math.round((done / total) * 100) : 0;
  const topStreaks = habits
    .map((h) => ({ ...h, streak: getStreak(h) }))
    .sort((a, b) => b.streak - a.streak)
    .slice(0, 4);

  if (total === 0)
    return (
      <div
        style={{
          display: 'flex',
          flexDirection: 'column',
          alignItems: 'center',
          justifyContent: 'center',
          height: '100%',
          gap: 8,
          cursor: 'pointer',
        }}
        onClick={() => activateApp('habits')}
      >
        <svg
          width="32"
          height="32"
          viewBox="0 0 24 24"
          fill="none"
          stroke={t.textMuted}
          strokeWidth="1.5"
          strokeLinecap="round"
          strokeLinejoin="round"
        >
          <circle cx="12" cy="12" r="10" />
          <circle cx="12" cy="12" r="6" />
          <circle cx="12" cy="12" r="2" />
        </svg>
        <div
          style={{
            fontSize: 12,
            fontWeight: 700,
            color: t.textMuted,
            textAlign: 'center',
          }}
        >
          No habits yet
        </div>
        <div style={{ fontSize: 11, color: t.textLight, textAlign: 'center' }}>
          Tap to add your first habit
        </div>
      </div>
    );

  return (
    <div
      style={{
        display: 'flex',
        flexDirection: 'column',
        height: '100%',
        gap: 10,
      }}
    >
      {/* Header row: ring + today count */}
      <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
        <div
          style={{ position: 'relative', width: 56, height: 56, flexShrink: 0 }}
        >
          <svg viewBox="0 0 56 56" style={{ transform: 'rotate(-90deg)' }}>
            <circle
              cx="28"
              cy="28"
              r="22"
              fill="none"
              stroke={t.border}
              strokeWidth="5"
            />
            <circle
              cx="28"
              cy="28"
              r="22"
              fill="none"
              stroke={color}
              strokeWidth="5"
              strokeDasharray={`${2 * Math.PI * 22}`}
              strokeDashoffset={`${2 * Math.PI * 22 * (1 - pct / 100)}`}
              strokeLinecap="round"
              style={{ transition: 'stroke-dashoffset 0.6s ease' }}
            />
          </svg>
          <div
            style={{
              position: 'absolute',
              inset: 0,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
              fontWeight: 900,
              fontSize: 13,
              color,
            }}
          >
            {pct}%
          </div>
        </div>
        <div>
          <div style={{ fontWeight: 900, fontSize: 22, color, lineHeight: 1 }}>
            {done}
            <span style={{ fontSize: 13, fontWeight: 600, color: t.textMuted }}>
              /{total}
            </span>
          </div>
          <div style={{ fontSize: 11, color: t.textMuted, marginTop: 2 }}>
            habits done today
          </div>
          <div style={{ fontSize: 10, color: t.textLight, marginTop: 1 }}>
            {pct === 100
              ? '🎉 Perfect day!'
              : pct >= 50
              ? 'Over halfway there!'
              : 'Keep going!'}
          </div>
        </div>
      </div>

      {/* Habit rows */}
      <div
        style={{
          display: 'flex',
          flexDirection: 'column',
          gap: 5,
          flex: 1,
          overflow: 'hidden',
        }}
      >
        {topStreaks.map((h) => {
          const isDone = !!h.completions?.[today];
          return (
            <div
              key={h.id}
              style={{
                display: 'flex',
                alignItems: 'center',
                gap: 8,
                padding: '5px 8px',
                borderRadius: 9,
                background: isDone ? h.color + '15' : t.surface,
                border: `1px solid ${isDone ? h.color + '44' : t.border}`,
                transition: 'all 0.15s',
              }}
            >
              <div
                style={{
                  width: 26,
                  height: 26,
                  borderRadius: 7,
                  background: isDone ? h.color : 'transparent',
                  border: `2px solid ${isDone ? h.color : t.border}`,
                  display: 'flex',
                  alignItems: 'center',
                  justifyContent: 'center',
                  fontSize: 13,
                  flexShrink: 0,
                  transition: 'all 0.15s',
                }}
              >
                {isDone ? '✓' : h.icon}
              </div>
              <div style={{ flex: 1, minWidth: 0 }}>
                <div
                  style={{
                    fontWeight: 700,
                    fontSize: 12,
                    color: t.text,
                    overflow: 'hidden',
                    textOverflow: 'ellipsis',
                    whiteSpace: 'nowrap',
                  }}
                >
                  {h.name}
                </div>
              </div>
              {/* mini 7-day dots */}
              <div style={{ display: 'flex', gap: 3, alignItems: 'center' }}>
                {last7.map((d) => (
                  <div
                    key={d}
                    style={{
                      width: 7,
                      height: 7,
                      borderRadius: '50%',
                      background: h.completions?.[d] ? h.color : t.border,
                      transition: 'all 0.1s',
                    }}
                  />
                ))}
              </div>
              {h.streak > 0 && (
                <span
                  style={{
                    fontSize: 10,
                    fontWeight: 800,
                    color: h.color,
                    flexShrink: 0,
                  }}
                >
                  🔥{h.streak}
                </span>
              )}
            </div>
          );
        })}
      </div>

      {/* Open app link */}
      <div
        onClick={() => activateApp('habits')}
        style={{
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          gap: 4,
          cursor: 'pointer',
          paddingTop: 2,
        }}
      >
        <span style={{ fontSize: 11, fontWeight: 700, color }}>
          View all habits
        </span>
        <Icon d={Icons.chevron} size={11} stroke={color} />
      </div>
    </div>
  );
}

function WidgetContent({ id, t, color, notes, activateApp, size }) {
  switch (id) {
    case 'todo':
      return (
        <WidgetTodo
          t={t}
          color={color}
          notes={notes}
          activateApp={activateApp}
        />
      );
    case 'notes':
      return (
        <WidgetNotes
          t={t}
          color={color}
          notes={notes}
          activateApp={activateApp}
        />
      );
    case 'calendar':
      return <WidgetCalendar t={t} color={color} activateApp={activateApp} />;
    case 'weather':
      return <WidgetWeather t={t} color={color} />;
    case 'clock':
      return <WidgetClock t={t} color={color} size={size} />;
    case 'reminders':
      return <WidgetReminders t={t} color={color} activateApp={activateApp} />;
    case 'quicknote':
      return <WidgetQuickNote t={t} color={color} />;
    case 'bookmarks':
      return <WidgetBookmarks t={t} color={color} activateApp={activateApp} />;
    case 'calculator':
      return <WidgetCalculator t={t} color={color} />;
    case 'habits':
      return <WidgetHabits t={t} color={color} activateApp={activateApp} />;
    case 'subscriptions':
      return (
        <WidgetSubscriptions t={t} color={color} activateApp={activateApp} />
      );
    default:
      return (
        <div style={{ color: t.textMuted, fontSize: 12 }}>Unknown widget</div>
      );
  }
}

