function WidgetsToggle({ t, activateApp, notes, appColors }) {
  const [showWidgets, setShowWidgets] = useState(() =>
    load('widgetsVisible', true)
  );
  const toggle = () => {
    const v = !showWidgets;
    setShowWidgets(v);
    save('widgetsVisible', v);
  };
  return (
    <div>
      <div
        onClick={toggle}
        style={{
          display: 'flex',
          alignItems: 'center',
          gap: 6,
          cursor: 'pointer',
          padding: '4px 0 8px',
          userSelect: 'none',
        }}
      >
        <span
          style={{
            fontSize: 12,
            fontWeight: 800,
            color: t.textMuted,
            textTransform: 'uppercase',
            letterSpacing: 0.5,
          }}
        >
          Widgets
        </span>
        <div
          style={{
            transform: showWidgets ? 'rotate(90deg)' : 'none',
            transition: 'transform 0.2s',
            color: t.textMuted,
            display: 'flex',
          }}
        >
          <Icon d={Icons.chevron} size={12} strokeWidth={2.5} />
        </div>
      </div>
      {showWidgets && (
        <WidgetBoard
          t={t}
          activateApp={activateApp}
          notes={notes}
          appColors={appColors}
          hideHeader
        />
      )}
    </div>
  );
}

function DashboardNavItem({ t, activeApp, activateApp, appLabels }) {
  const [pressed, setPressed] = useState(false);
  const homeActive = activeApp === 'home';
  return (
    <div
      onClick={() => {
        setPressed(true);
        setTimeout(() => setPressed(false), 300);
        activateApp('home');
      }}
      style={{
        display: 'flex',
        alignItems: 'center',
        gap: 9,
        padding: '7px 10px',
        borderRadius: 9,
        cursor: 'pointer',
        marginBottom: 6,
        background: homeActive ? t.accent : t.surface,
        border: `1px solid ${homeActive ? t.accent : t.border}`,
        transform: pressed ? 'scale(0.97)' : 'scale(1)',
        boxShadow: homeActive ? '0 3px 10px rgba(47,107,255,0.22)' : 'none',
        transition:
          'transform 0.15s cubic-bezier(0.34,1.56,0.64,1), background 0.15s, box-shadow 0.15s',
      }}
      onMouseEnter={(e) => {
        if (!homeActive) {
          e.currentTarget.style.background = t.surfaceHover;
        }
      }}
      onMouseLeave={(e) => {
        if (!homeActive) {
          e.currentTarget.style.background = t.surface;
        }
      }}
    >
      <div
        style={{
          width: 24,
          height: 24,
          borderRadius: 7,
          flexShrink: 0,
          background: homeActive ? 'rgba(255,255,255,0.2)' : '#2f6bff22',
          display: 'flex',
          alignItems: 'center',
          justifyContent: 'center',
          transform: pressed ? 'rotate(-8deg) scale(1.12)' : 'scale(1)',
          transition: 'transform 0.25s cubic-bezier(0.34,1.56,0.64,1)',
        }}
      >
        <Icon
          d={Icons.home2}
          size={13}
          stroke={homeActive ? '#fff' : '#2f6bff'}
          strokeWidth={2.2}
        />
      </div>
      <span
        style={{
          fontSize: 13,
          fontWeight: 700,
          flex: 1,
          color: homeActive ? '#fff' : t.text,
        }}
      >
        {appLabels['home'] || 'Dashboard'}
      </span>
    </div>
  );
}

function SidebarGroupCard({
  t,
  group,
  dropGroup,
  dragGroup,
  toggleGroup,
  appLabels,
  disabledApps,
  activateApp,
  isAppActive,
  dragItem,
  setDragItem,
  dropTarget,
  setDropTarget,
  handleItemDrop,
  ICON_MAP2,
}) {
  const [pressed, setPressed] = useState(false);
  const gc = group.color || '#6b7280';
  const giconD = GROUP_ICON_MAP[group.icon] || GROUP_ICON_MAP['folder'];
  const isDropTarget = dropGroup === group.id && dragGroup !== group.id;
  return (
    <div>
      {/* Main card — slimmer height */}
      <div
        onClick={() => {
          setPressed(true);
          setTimeout(() => setPressed(false), 300);
          toggleGroup(group.id);
        }}
        style={{
          display: 'flex',
          alignItems: 'center',
          gap: 9,
          padding: '7px 10px',
          borderRadius: 9,
          cursor: 'pointer',
          background: isDropTarget ? gc + '18' : t.surface,
          border: `1px solid ${isDropTarget ? gc : t.border}`,
          transform: pressed ? 'scale(0.97)' : 'scale(1)',
          transition:
            'transform 0.15s cubic-bezier(0.34,1.56,0.64,1), background 0.12s, border-color 0.12s',
        }}
        onMouseEnter={(e) => {
          e.currentTarget.style.background = gc + '15';
          e.currentTarget.style.borderColor = gc + '55';
        }}
        onMouseLeave={(e) => {
          e.currentTarget.style.background = isDropTarget
            ? gc + '18'
            : t.surface;
          e.currentTarget.style.borderColor = isDropTarget ? gc : t.border;
        }}
      >
        <div
          style={{
            width: 24,
            height: 24,
            borderRadius: 7,
            flexShrink: 0,
            background: gc + '22',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            transform: pressed ? 'rotate(-8deg) scale(1.12)' : 'scale(1)',
            transition: 'transform 0.25s cubic-bezier(0.34,1.56,0.64,1)',
          }}
        >
          <Icon d={giconD} size={13} stroke={gc} strokeWidth={2} />
        </div>
        <span style={{ fontSize: 13, fontWeight: 700, flex: 1, color: t.text }}>
          {group.label}
        </span>
        <div
          style={{
            transform: group.collapsed ? 'rotate(0deg)' : 'rotate(90deg)',
            transition: 'transform 0.22s ease',
            color: t.textMuted,
            display: 'flex',
            flexShrink: 0,
          }}
        >
          <Icon d={Icons.chevron} size={11} strokeWidth={2.5} />
        </div>
      </div>
      {/* Items */}
      {!group.collapsed && (
        <div
          style={{
            marginTop: 2,
            marginLeft: 4,
            borderLeft: `2px solid ${gc}22`,
            paddingLeft: 6,
          }}
        >
          {group.items
            .filter(
              (key) =>
                !disabledApps.includes(key) &&
                key !== 'home' &&
                key !== 'settings' &&
                key !== 'trash'
            )
            .map((key) => {
              const item = ALL_APP_ITEMS.find((i) => i.key === key);
              if (!item) return null;
              const active = isAppActive(key);
              const isDrop =
                dropTarget?.groupId === group.id && dropTarget?.key === key;
              return (
                <div
                  key={key}
                  draggable
                  onDragStart={(e) => {
                    e.stopPropagation();
                    setDragItem({ groupId: group.id, key });
                  }}
                  onDragOver={(e) => {
                    e.preventDefault();
                    e.stopPropagation();
                    setDropTarget({ groupId: group.id, key });
                  }}
                  onDrop={(e) => {
                    e.preventDefault();
                    e.stopPropagation();
                    handleItemDrop(group.id, key);
                  }}
                  onDragEnd={() => {
                    setDragItem(null);
                    setDropTarget(null);
                  }}
                  onClick={() => activateApp(key)}
                  style={{
                    display: 'flex',
                    alignItems: 'center',
                    gap: 8,
                    padding: '5px 8px 5px 8px',
                    borderRadius: 7,
                    cursor: 'pointer',
                    margin: '1px 0',
                    background: active ? gc + '18' : 'none',
                    borderTop:
                      isDrop && dragItem?.key !== key
                        ? `2px solid ${gc}`
                        : '2px solid transparent',
                    opacity: dragItem?.key === key ? 0.4 : 1,
                    transition: 'background 0.1s,opacity 0.1s',
                  }}
                  onMouseEnter={(e) => {
                    if (!active) e.currentTarget.style.background = gc + '10';
                  }}
                  onMouseLeave={(e) => {
                    if (!active) e.currentTarget.style.background = 'none';
                  }}
                >
                  <Icon
                    d={ICON_MAP2[item.icon] || Icons.notes}
                    size={13}
                    stroke={active ? gc : t.iconStroke || t.text}
                    strokeWidth={active ? 2.2 : 1.8}
                  />
                  <span
                    style={{
                      fontSize: 12,
                      fontWeight: active ? 700 : 500,
                      flex: 1,
                      color: active ? gc : t.text,
                    }}
                  >
                    {appLabels[key] || item.label}
                  </span>
                </div>
              );
            })}
          <div
            onDragOver={(e) => {
              e.preventDefault();
              setDropTarget({ groupId: group.id, key: '__end__' });
            }}
            onDrop={(e) => {
              e.preventDefault();
              handleItemDrop(group.id, '__end__');
            }}
            style={{
              height:
                dropTarget?.groupId === group.id &&
                dropTarget?.key === '__end__' &&
                dragItem
                  ? 5
                  : 1,
              borderRadius: 3,
              background:
                dropTarget?.groupId === group.id &&
                dropTarget?.key === '__end__' &&
                dragItem
                  ? gc
                  : 'transparent',
              margin: '1px 8px',
              transition: 'all 0.1s',
            }}
          />
        </div>
      )}
    </div>
  );
}

function WidgetBoard({ t, activateApp, notes, appColors, hideHeader = false }) {
  const confirmDlg = useConfirm();
  const [layout, setLayout] = useState(() => {
    const saved = load('widgetLayout2', null);
    if (!saved) return DEFAULT_WIDGET_LAYOUT_NEW;
    // If saved layout is missing any widgets, reset to full default
    const savedIds = new Set(saved.map((w) => w.id));
    const allIds = ALL_WIDGETS.map((w) => w.id);
    if (allIds.some((id) => !savedIds.has(id)))
      return DEFAULT_WIDGET_LAYOUT_NEW;
    // migrate old size format
    return saved.map((w) => ({
      ...w,
      size:
        { S: 1, M: 2, L: 3, '2x2': 'S', '2x4': 'M', '2x8': 'L' }[w.size] ||
        w.size ||
        'S',
    }));
  });
  const [colors, setColors] = useState(() => load('widgetColors', {}));
  const [bgColors, setBgColors] = useState(() => load('widgetBgColors', {}));
  const [showAdd, setShowAdd] = useState(false);
  const [editingId, setEditingId] = useState(null);
  const [dragIdx, setDragIdx] = useState(null);
  const [dragOverIdx, setDragOverIdx] = useState(null);

  useEffect(() => save('widgetLayout2', layout), [layout]);
  useEffect(() => save('widgetColors', colors), [colors]);
  useEffect(() => save('widgetBgColors', bgColors), [bgColors]);

  const PALETTE = [
    '#2f6bff',
    '#e84040',
    '#16a34a',
    '#d97706',
    '#9333ea',
    '#0891b2',
    '#db2777',
    '#65a30d',
    '#6b7280',
    '#f59e0b',
    '#10b981',
    '#f97316',
    '#8b5cf6',
    '#06b6d4',
    '#ec4899',
    '#0f172a',
  ];

  const addWidget = (widgetId, size = 'S') => {
    const def = ALL_WIDGETS.find((w) => w.id === widgetId);
    if (!def) return;
    setLayout((p) => [
      ...p,
      { id: widgetId, instanceId: widgetId + '-' + genId(), size },
    ]);
    setShowAdd(false);
  };

  const removeWidget = (instanceId) =>
    confirmDlg({
      key: 'del-widget',
      title: 'Remove Widget',
      msg: 'Remove this widget from the dashboard?',
      confirmLabel: 'Remove Widget',
      icon: 'trash',
      onOk: () =>
        setLayout((p) => p.filter((w) => w.instanceId !== instanceId)),
    });
  const setWidgetSize = (instanceId, size) =>
    setLayout((p) =>
      p.map((w) => (w.instanceId === instanceId ? { ...w, size } : w))
    );
  const setWidgetColor = (instanceId, color) => {
    setColors((p) => ({ ...p, [instanceId]: color }));
    setEditingId(null);
  };
  const setWidgetBg = (instanceId, bg) => {
    setBgColors((p) => ({ ...p, [instanceId]: bg }));
  };

  const onDragStart = (i) => setDragIdx(i);
  const onDragOver = (e, i) => {
    e.preventDefault();
    setDragOverIdx(i);
  };
  const onDrop = (i) => {
    if (dragIdx === null || dragIdx === i) return;
    const newL = [...layout];
    const [moved] = newL.splice(dragIdx, 1);
    newL.splice(i, 0, moved);
    setLayout(newL);
    setDragIdx(null);
    setDragOverIdx(null);
  };

  return (
    <div onClick={() => editingId && setEditingId(null)}>
      {/* Toolbar */}
      <div
        style={{
          display: 'flex',
          alignItems: 'center',
          gap: 10,
          marginBottom: 12,
          flexWrap: 'wrap',
        }}
      >
        {!hideHeader && (
          <span
            style={{
              fontSize: 12,
              fontWeight: 800,
              color: t.textMuted,
              textTransform: 'uppercase',
              letterSpacing: 0.5,
            }}
          >
            Widgets
          </span>
        )}
        {!hideHeader && (
          <div style={{ fontSize: 11, color: t.textLight }}>
            Drag to reorder · S / M / L sizes
          </div>
        )}
        <div style={{ flex: 1 }} />
        <button
          onClick={(e) => {
            e.stopPropagation();
            setShowAdd((p) => !p);
          }}
          style={{
            padding: '7px 14px',
            border: `1px solid ${showAdd ? t.accent : t.border}`,
            borderRadius: 9,
            background: showAdd ? t.accentBg : 'none',
            color: showAdd ? t.accent : t.textMuted,
            cursor: 'pointer',
            fontSize: 12,
            fontWeight: 700,
            display: 'flex',
            alignItems: 'center',
            gap: 5,
          }}
        >
          <Icon d={Icons.plus} size={13} /> Add Widget
        </button>
      </div>

      {/* Add widget panel */}
      {showAdd && (
        <div
          onClick={(e) => e.stopPropagation()}
          style={{
            background: t.card,
            borderRadius: 16,
            border: `1px solid ${t.accent}`,
            padding: '16px 18px',
            marginBottom: 16,
            boxShadow: t.shadowMd,
          }}
        >
          <div
            style={{
              fontWeight: 800,
              fontSize: 13,
              color: t.text,
              marginBottom: 4,
            }}
          >
            Choose a widget
          </div>
          <div style={{ fontSize: 11, color: t.textMuted, marginBottom: 12 }}>
            <strong>S</strong> = half-width short &nbsp;·&nbsp;{' '}
            <strong>M</strong> = half-width tall &nbsp;·&nbsp;{' '}
            <strong>L</strong> = full-width
          </div>
          <div style={{ display: 'flex', flexDirection: 'column', gap: 6 }}>
            {ALL_WIDGETS.map((w) => (
              <div
                key={w.id}
                style={{
                  display: 'flex',
                  alignItems: 'center',
                  gap: 10,
                  padding: '10px 12px',
                  border: `1px solid ${t.border}`,
                  borderRadius: 10,
                  background: t.surface,
                }}
              >
                <span style={{ fontSize: 20, flexShrink: 0 }}>{w.emoji}</span>
                <div style={{ flex: 1, minWidth: 0 }}>
                  <div style={{ fontSize: 12, fontWeight: 700, color: t.text }}>
                    {w.label}
                  </div>
                  <div style={{ fontSize: 10, color: t.textMuted }}>
                    {w.desc}
                  </div>
                </div>
                <div style={{ display: 'flex', gap: 5, flexShrink: 0 }}>
                  {WIDGET_SIZES.map((sz) => (
                    <button
                      key={sz.id}
                      onClick={() => addWidget(w.id, sz.id)}
                      style={{
                        padding: '5px 12px',
                        border: `1px solid ${w.defaultColor}`,
                        borderRadius: 7,
                        background: w.defaultColor + '18',
                        color: w.defaultColor,
                        cursor: 'pointer',
                        fontSize: 11,
                        fontWeight: 800,
                        transition: 'all 0.12s',
                      }}
                      onMouseEnter={(e) => {
                        e.currentTarget.style.background = w.defaultColor;
                        e.currentTarget.style.color = '#fff';
                      }}
                      onMouseLeave={(e) => {
                        e.currentTarget.style.background =
                          w.defaultColor + '18';
                        e.currentTarget.style.color = w.defaultColor;
                      }}
                    >
                      {sz.label}
                    </button>
                  ))}
                </div>
              </div>
            ))}
          </div>
        </div>
      )}

      {/* Empty state */}
      {layout.length === 0 && (
        <div
          style={{
            textAlign: 'center',
            padding: '48px 0',
            color: t.textMuted,
            background: t.card,
            borderRadius: 20,
            border: `2px dashed ${t.border}`,
          }}
        >
          <svg
            width="36"
            height="36"
            viewBox="0 0 24 24"
            fill="none"
            stroke={t.textMuted}
            strokeWidth="1.5"
            strokeLinecap="round"
            strokeLinejoin="round"
            style={{ marginBottom: 12 }}
          >
            <path d="M18 20V10M12 20V4M6 20v-6" />
          </svg>
          <div
            style={{
              fontSize: 14,
              fontWeight: 700,
              color: t.text,
              marginBottom: 6,
            }}
          >
            No widgets yet
          </div>
          <div style={{ fontSize: 12 }}>
            Click "Add Widget" above to get started
          </div>
        </div>
      )}

      {/* Grid — always 4 columns, fixed heights per size */}
      <div
        style={{
          display: 'grid',
          gridTemplateColumns: 'repeat(8,1fr)',
          gap: 14,
          alignItems: 'start',
        }}
      >
        {layout.map((w, i) => {
          const def = ALL_WIDGETS.find((x) => x.id === w.id);
          if (!def) return null;
          const instanceId = w.instanceId || w.id;
          const color = colors[instanceId] || def.defaultColor;
          const sz =
            WIDGET_SIZES.find((s) => s.id === (w.size || 'S')) ||
            WIDGET_SIZES[0];
          const isDragOver = dragOverIdx === i && dragIdx !== i;
          const bg = bgColors[instanceId] || t.card;
          // Determine if bg is dark to ensure readable text
          const isDarkBg = (() => {
            const hex = bg.replace('#', '');
            if (hex.length < 6) return false;
            const r = parseInt(hex.slice(0, 2), 16),
              g = parseInt(hex.slice(2, 4), 16),
              b = parseInt(hex.slice(4, 6), 16);
            return r * 0.299 + g * 0.587 + b * 0.114 < 128;
          })();
          const textOnBg = isDarkBg ? '#ffffff' : t.text;
          const mutedOnBg = isDarkBg ? 'rgba(255,255,255,0.6)' : t.textMuted;
          const borderOnBg = isDarkBg ? 'rgba(255,255,255,0.15)' : t.border;
          return (
            <div
              key={instanceId}
              draggable
              onDragStart={() => onDragStart(i)}
              onDragOver={(e) => onDragOver(e, i)}
              onDrop={() => onDrop(i)}
              onDragEnd={() => {
                setDragIdx(null);
                setDragOverIdx(null);
              }}
              style={{
                gridColumn: `span ${sz.cols}`,
                height: sz.h,
                opacity: dragIdx === i ? 0.4 : 1,
                outline: isDragOver
                  ? `2px dashed ${t.accent}`
                  : '2px solid transparent',
                borderRadius: 20,
                position: 'relative',
                transition: 'opacity 0.15s',
                flexShrink: 0,
              }}
            >
              <div
                style={{
                  background: bg,
                  borderRadius: 20,
                  border: `1px solid ${borderOnBg}`,
                  padding: '14px 16px',
                  boxShadow: t.shadow,
                  height: '100%',
                  boxSizing: 'border-box',
                  display: 'flex',
                  flexDirection: 'column',
                  overflow: 'hidden',
                }}
              >
                {/* Widget header */}
                <div
                  style={{
                    display: 'flex',
                    alignItems: 'center',
                    gap: 7,
                    marginBottom: 10,
                    cursor: 'grab',
                    flexShrink: 0,
                  }}
                >
                  <div
                    style={{
                      width: 28,
                      height: 28,
                      borderRadius: 8,
                      background: color + '33',
                      border: `1px solid ${color}55`,
                      display: 'flex',
                      alignItems: 'center',
                      justifyContent: 'center',
                      flexShrink: 0,
                    }}
                  >
                    <span style={{ fontSize: 13 }}>{def.emoji}</span>
                  </div>
                  <span
                    style={{
                      fontSize: 12,
                      fontWeight: 800,
                      color: textOnBg,
                      flex: 1,
                      minWidth: 0,
                      overflow: 'hidden',
                      textOverflow: 'ellipsis',
                      whiteSpace: 'nowrap',
                    }}
                  >
                    {def.label}
                  </span>

                  {/* Size picker — S / M / L */}
                  <div style={{ display: 'flex', gap: 3, flexShrink: 0 }}>
                    {WIDGET_SIZES.map((sz2) => {
                      const active = (w.size || 'S') === sz2.id;
                      return (
                        <button
                          key={sz2.id}
                          onClick={(e) => {
                            e.stopPropagation();
                            setWidgetSize(instanceId, sz2.id);
                          }}
                          style={{
                            width: 22,
                            height: 20,
                            border: `1px solid ${active ? color : borderOnBg}`,
                            borderRadius: 5,
                            background: active ? color : 'transparent',
                            color: active ? '#fff' : mutedOnBg,
                            cursor: 'pointer',
                            fontSize: 9,
                            fontWeight: 800,
                            transition: 'all 0.12s',
                            padding: 0,
                          }}
                        >
                          {sz2.label}
                        </button>
                      );
                    })}
                  </div>

                  {/* Color dot — opens picker */}
                  <div style={{ position: 'relative', flexShrink: 0 }}>
                    <button
                      onClick={(e) => {
                        e.stopPropagation();
                        setEditingId(
                          editingId === instanceId ? null : instanceId
                        );
                      }}
                      style={{
                        width: 16,
                        height: 16,
                        borderRadius: '50%',
                        background: color,
                        border: `2px solid ${borderOnBg}`,
                        cursor: 'pointer',
                        display: 'block',
                      }}
                    />
                    {editingId === instanceId && (
                      <div
                        onClick={(e) => e.stopPropagation()}
                        style={{
                          position: 'absolute',
                          top: 'calc(100% + 6px)',
                          right: 0,
                          zIndex: 200,
                          background: t.sidebar,
                          border: `1px solid ${t.border}`,
                          borderRadius: 14,
                          padding: '12px',
                          boxShadow: t.shadowMd,
                          width: 172,
                        }}
                      >
                        {/* Accent color (icon tint) */}
                        <div
                          style={{
                            fontSize: 10,
                            fontWeight: 800,
                            color: t.textMuted,
                            marginBottom: 6,
                            textTransform: 'uppercase',
                            letterSpacing: 0.5,
                          }}
                        >
                          Accent Color
                        </div>
                        <div
                          style={{
                            display: 'flex',
                            flexWrap: 'wrap',
                            gap: 5,
                            marginBottom: 10,
                          }}
                        >
                          {PALETTE.map((c) => (
                            <button
                              key={c}
                              onClick={() => setWidgetColor(instanceId, c)}
                              style={{
                                width: 20,
                                height: 20,
                                borderRadius: '50%',
                                background: c,
                                border: `2px solid ${
                                  c === color ? t.text : 'transparent'
                                }`,
                                cursor: 'pointer',
                                padding: 0,
                              }}
                            />
                          ))}
                        </div>

                        {/* Background color */}
                        <div
                          style={{
                            fontSize: 10,
                            fontWeight: 800,
                            color: t.textMuted,
                            marginBottom: 6,
                            textTransform: 'uppercase',
                            letterSpacing: 0.5,
                          }}
                        >
                          Background
                        </div>
                        <div
                          style={{ display: 'flex', gap: 5, marginBottom: 4 }}
                        >
                          {[
                            { c: '#000000', label: 'Black' },
                            { c: '#1b2a45', label: 'Navy' },
                            { c: '#2f8072', label: 'Teal' },
                            { c: '#ffffff', label: 'White' },
                            { c: '#fef9c3', label: 'Yellow' },
                            { c: '#d1fae5', label: 'Green' },
                          ].map(({ c, label }) => (
                            <button
                              key={label}
                              onClick={() => setWidgetBg(instanceId, c)}
                              title={label}
                              style={{
                                width: 24,
                                height: 24,
                                borderRadius: 6,
                                background: c,
                                flexShrink: 0,
                                border: `2px solid ${
                                  bg === c ? t.accent : t.border
                                }`,
                                cursor: 'pointer',
                                padding: 0,
                              }}
                            />
                          ))}
                        </div>
                        <div
                          style={{
                            display: 'flex',
                            gap: 5,
                            marginBottom: 8,
                            alignItems: 'center',
                          }}
                        >
                          <button
                            onClick={() =>
                              setBgColors((p) => {
                                const n = { ...p };
                                delete n[instanceId];
                                return n;
                              })
                            }
                            title="Default"
                            style={{
                              height: 24,
                              padding: '0 8px',
                              borderRadius: 6,
                              background: t.card,
                              flexShrink: 0,
                              border: `2px solid ${
                                !bgColors[instanceId] ? t.accent : t.border
                              }`,
                              cursor: 'pointer',
                              fontSize: 9,
                              color: t.textMuted,
                              fontWeight: 800,
                            }}
                          >
                            Default
                          </button>
                          <input
                            type="color"
                            value={bg === t.card ? '#ffffff' : bg}
                            onChange={(e) =>
                              setWidgetBg(instanceId, e.target.value)
                            }
                            title="Custom"
                            style={{
                              flex: 1,
                              height: 24,
                              borderRadius: 6,
                              border: `2px solid ${t.border}`,
                              cursor: 'pointer',
                              padding: 0,
                              boxSizing: 'border-box',
                            }}
                          />
                        </div>
                        <button
                          onClick={() => {
                            setWidgetColor(instanceId, def.defaultColor);
                            setBgColors((p) => {
                              const n = { ...p };
                              delete n[instanceId];
                              return n;
                            });
                            setEditingId(null);
                          }}
                          style={{
                            width: '100%',
                            padding: '4px',
                            border: `1px solid ${t.border}`,
                            borderRadius: 5,
                            background: 'none',
                            color: t.textMuted,
                            cursor: 'pointer',
                            fontSize: 9,
                            fontWeight: 700,
                          }}
                        >
                          Reset all
                        </button>
                      </div>
                    )}
                  </div>

                  {/* Delete */}
                  <button
                    onClick={(e) => {
                      e.stopPropagation();
                      removeWidget(instanceId);
                    }}
                    style={{
                      background: 'none',
                      border: 'none',
                      cursor: 'pointer',
                      color: mutedOnBg,
                      padding: 2,
                      borderRadius: 5,
                      display: 'flex',
                      flexShrink: 0,
                    }}
                    onMouseEnter={(e) =>
                      (e.currentTarget.style.color = '#e84040')
                    }
                    onMouseLeave={(e) =>
                      (e.currentTarget.style.color = mutedOnBg)
                    }
                  >
                    <Icon d={Icons.x} size={12} strokeWidth={2.5} />
                  </button>
                </div>

                {/* Content — pass textOnBg so widget content also respects bg */}
                <div
                  style={{
                    flex: 1,
                    minHeight: 0,
                    overflow: 'auto',
                    scrollbarWidth: 'none',
                    msOverflowStyle: 'none',
                  }}
                  className="hide-scrollbar"
                >
                  <WidgetContent
                    id={w.id}
                    t={{
                      ...t,
                      text: textOnBg,
                      textMuted: mutedOnBg,
                      border: borderOnBg,
                      card: bg,
                      surface: isDarkBg
                        ? 'rgba(255,255,255,0.08)'
                        : 'rgba(0,0,0,0.04)',
                      surfaceHover: isDarkBg
                        ? 'rgba(255,255,255,0.12)'
                        : 'rgba(0,0,0,0.07)',
                    }}
                    color={color}
                    notes={notes}
                    activateApp={activateApp}
                    size={w.size || 'S'}
                  />
                </div>
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

