// ─── SYNC MODAL ───────────────────────────────────────────────────────────────
function SyncModal({ t, onClose, notes, setNotes, notify, inline }) {
  const [syncKey, setSyncKey] = useState(() => load('syncKey', ''));
  const [inputKey, setInputKey] = useState(load('syncKey', ''));
  const [status, setStatus] = useState('');
  const [loading, setLoading] = useState(false);
  const [lastSync, setLastSync] = useState(() => load('lastSync', null));

  // We use jsonbin.io — free, no signup needed for read, just need a bin ID
  // Users create a free account at jsonbin.io to get an API key + bin ID
  const JSONBIN_BASE = 'https://api.jsonbin.io/v3/b';

  const getDataToSync = () => {
    return {
      notes: load('notes', []),
      folders: load('folders', []),
      todoLists: load('todoLists', []),
      bookmarks: load('bookmarks', []),
      contacts: load('contacts', []),
      categories: load('categories', []),
      syncedAt: new Date().toISOString(),
    };
  };

  const applySync = (data) => {
    if (data.notes) {
      save('notes', data.notes);
      setNotes(data.notes);
    }
    if (data.folders) save('folders', data.folders);
    if (data.todoLists) save('todoLists', data.todoLists);
    if (data.bookmarks) save('bookmarks', data.bookmarks);
    if (data.contacts) save('contacts', data.contacts);
    if (data.categories) save('categories', data.categories);
  };

  const saveKey = () => {
    save('syncKey', inputKey.trim());
    setSyncKey(inputKey.trim());
    setStatus('✅ Sync key saved');
  };

  // Upload current data to jsonbin
  const pushSync = async () => {
    if (!syncKey) {
      setStatus('❌ Enter your Bin ID and API Key first');
      return;
    }
    const [binId, apiKey] = syncKey.split('|');
    if (!binId || !apiKey) {
      setStatus('❌ Format: BINID|APIKEY');
      return;
    }
    setLoading(true);
    setStatus('Uploading…');
    try {
      const res = await fetch(`${JSONBIN_BASE}/${binId}`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json', 'X-Master-Key': apiKey },
        body: JSON.stringify(getDataToSync()),
      });
      if (res.ok) {
        const now = new Date().toISOString();
        save('lastSync', now);
        setLastSync(now);
        setStatus('✅ Data pushed successfully!');
        notify('Sync pushed!');
      } else setStatus(`❌ Error ${res.status}: ${await res.text()}`);
    } catch (e) {
      setStatus('❌ Network error: ' + e.message);
    }
    setLoading(false);
  };

  // Download data from jsonbin
  const pullSync = async () => {
    if (!syncKey) {
      setStatus('❌ Enter your Bin ID and API Key first');
      return;
    }
    const [binId, apiKey] = syncKey.split('|');
    if (!binId || !apiKey) {
      setStatus('❌ Format: BINID|APIKEY');
      return;
    }
    setLoading(true);
    setStatus('Downloading…');
    try {
      const res = await fetch(`${JSONBIN_BASE}/${binId}/latest`, {
        headers: { 'X-Master-Key': apiKey },
      });
      if (res.ok) {
        const json = await res.json();
        applySync(json.record);
        const now = new Date().toISOString();
        save('lastSync', now);
        setLastSync(now);
        setStatus('✅ Data pulled successfully!');
        notify('Sync pulled! Restart app to see all changes.');
      } else setStatus(`❌ Error ${res.status}: ${await res.text()}`);
    } catch (e) {
      setStatus('❌ Network error: ' + e.message);
    }
    setLoading(false);
  };

  const content = (
    <div style={inline ? {} : { padding: '28px 26px 24px' }}>
      {!inline && (
        <div
          style={{
            display: 'flex',
            alignItems: 'center',
            gap: 12,
            marginBottom: 22,
          }}
        >
          <div
            style={{
              width: 40,
              height: 40,
              borderRadius: 11,
              background: t.accentBg,
              display: 'flex',
              alignItems: 'center',
              justifyContent: 'center',
            }}
          >
            <Icon d={Icons.restore} size={20} stroke={t.accent} />
          </div>
          <div>
            <div style={{ fontWeight: 900, fontSize: 16, color: t.text }}>
              Online Sync
            </div>
            <div style={{ fontSize: 11, color: t.textMuted }}>
              Sync your data between devices using JSONBin
            </div>
          </div>
        </div>
      )}

      {/* How it works */}
      <div
        style={{
          background: t.surface,
          borderRadius: 12,
          padding: '14px 16px',
          marginBottom: 18,
          border: `1px solid ${t.border}`,
        }}
      >
        <div
          style={{
            fontSize: 12,
            fontWeight: 700,
            color: t.text,
            marginBottom: 8,
          }}
        >
          How to set up (free, 2 minutes):
        </div>
        <div style={{ fontSize: 12, color: t.textMuted, lineHeight: 1.8 }}>
          1. Go to{' '}
          <a
            href="https://jsonbin.io"
            target="_blank"
            rel="noopener noreferrer"
            style={{ color: t.accent }}
          >
            jsonbin.io
          </a>{' '}
          → Sign up free
          <br />
          2. Create a new Bin (click + New Bin, save empty JSON {'{}'})<br />
          3. Copy the <strong style={{ color: t.text }}>Bin ID</strong> from the
          URL
          <br />
          4. Go to API Keys → copy your{' '}
          <strong style={{ color: t.text }}>Master Key</strong>
          <br />
          5. Paste both below as:{' '}
          <code
            style={{
              background: t.bg,
              padding: '1px 5px',
              borderRadius: 4,
              fontSize: 11,
            }}
          >
            BINID|MASTERKEY
          </code>
        </div>
      </div>

      {/* Key input */}
      <div style={{ marginBottom: 12 }}>
        <div
          style={{
            fontSize: 11,
            fontWeight: 700,
            color: t.textMuted,
            marginBottom: 6,
            textTransform: 'uppercase',
            letterSpacing: 0.5,
          }}
        >
          Sync Key (BinID|MasterKey)
        </div>
        <div style={{ display: 'flex', gap: 8 }}>
          <input
            type="password"
            value={inputKey}
            onChange={(e) => setInputKey(e.target.value)}
            placeholder="e.g. 64abc123|$2a$10$..."
            style={{
              flex: 1,
              padding: '10px 14px',
              border: `1px solid ${syncKey === inputKey ? t.border : t.accent}`,
              borderRadius: 10,
              background: t.surface,
              color: t.text,
              fontSize: 13,
              outline: 'none',
            }}
          />
          <button
            onClick={saveKey}
            style={{
              padding: '10px 16px',
              border: 'none',
              borderRadius: 10,
              background: t.accent,
              color: '#fff',
              cursor: 'pointer',
              fontSize: 12,
              fontWeight: 800,
            }}
          >
            Save
          </button>
        </div>
      </div>

      {lastSync && (
        <div style={{ fontSize: 11, color: t.textMuted, marginBottom: 14 }}>
          Last synced: {new Date(lastSync).toLocaleString()}
        </div>
      )}

      {/* Status */}
      {status && (
        <div
          style={{
            fontSize: 12,
            padding: '8px 12px',
            borderRadius: 8,
            background: status.includes('✅')
              ? '#16a34a22'
              : status.includes('❌')
              ? '#e8404022'
              : t.surface,
            color: status.includes('✅')
              ? '#16a34a'
              : status.includes('❌')
              ? '#e84040'
              : t.text,
            marginBottom: 14,
            fontWeight: 600,
          }}
        >
          {status}
        </div>
      )}

      {/* Sync buttons */}
      <div
        style={{
          display: 'grid',
          gridTemplateColumns: '1fr 1fr',
          gap: 10,
          marginBottom: 14,
        }}
      >
        <button
          onClick={pushSync}
          disabled={loading}
          style={{
            padding: '12px',
            border: 'none',
            borderRadius: 12,
            background: t.accent,
            color: '#fff',
            cursor: loading ? 'not-allowed' : 'pointer',
            fontSize: 13,
            fontWeight: 800,
            opacity: loading ? 0.6 : 1,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            gap: 8,
          }}
        >
          <Icon d={Icons.export} size={14} stroke="#fff" /> Push to Cloud
        </button>
        <button
          onClick={pullSync}
          disabled={loading}
          style={{
            padding: '12px',
            border: `2px solid ${t.accent}`,
            borderRadius: 12,
            background: 'none',
            color: t.accent,
            cursor: loading ? 'not-allowed' : 'pointer',
            fontSize: 13,
            fontWeight: 800,
            opacity: loading ? 0.6 : 1,
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
            gap: 8,
          }}
        >
          <Icon d={Icons.import} size={14} stroke={t.accent} /> Pull from Cloud
        </button>
      </div>

      <div
        style={{
          fontSize: 11,
          color: t.textMuted,
          textAlign: 'center',
          lineHeight: 1.6,
        }}
      >
        <strong>Push</strong> = upload this device's data to cloud &nbsp;·&nbsp;{' '}
        <strong>Pull</strong> = download cloud data to this device
        <br />
        Use the same Bin ID + Key on all your devices
      </div>
    </div>
  );

  if (inline) return content;
  return (
    <Modal t={t} onClose={onClose} width={500}>
      {content}
    </Modal>
  );
}

