              padding: '5px 12px',
              border: `1px solid ${t.border}`,
              borderRadius: 7,
              background: t.surface,
              color: t.text,
              cursor: 'pointer',
              fontSize: 11,
              fontWeight: 700,
              display: 'flex',
              alignItems: 'center',
              gap: 5,
