// EXPORT DXF
// ═══════════════════════════════════════════════════════════════════
function exportDXF(){
  const L=[];L.push('0','SECTION','2','ENTITIES');
  function poly(pts,layer){L.push('0','LWPOLYLINE','8',layer,'70','1','90',String(pts.length));pts.forEach(p=>{L.push('10',p[0].toFixed(4),'20',p[1].toFixed(4));});}
  function txt(x,y,h,t2,layer){L.push('0','TEXT','8',layer,'10',x.toFixed(4),'20',y.toFixed(4),'30','0','40',h.toFixed(4),'1',t2);}
  function ln(x1,y1,x2,y2,layer){L.push('0','LINE','8',layer,'10',x1.toFixed(4),'20',y1.toFixed(4),'11',x2.toFixed(4),'21',y2.toFixed(4));}
  const pp=pxPerM();
  if(boundary&&showBoundary){const{x,y,w,h}=boundary;poly([[x/pp,-y/pp],[(x+w)/pp,-y/pp],[(x+w)/pp,-(y+h)/pp],[x/pp,-(y+h)/pp]],'BOUNDARY');}
  rooms.forEach(r=>{
    const x1=r.x/pp,y1=r.y/pp,x2=(r.x+r.w)/pp,y2=(r.y+r.h)/pp;const wt=r.wallThick||0.15;
    poly([[x1,-y1],[x2,-y1],[x2,-y2],[x1,-y2]],'WALLS');
    poly([[x1+wt,-y1-wt],[x2-wt,-y1-wt],[x2-wt,-y2+wt],[x1+wt,-y2+wt]],'WALLS_INNER');
    txt((x1+x2)/2,-(y1+y2)/2,0.2,r.name,'ANNOTATIONS');
    ln(x1,-y1+0.3,x2,-y1+0.3,'DIMENSIONS');txt((x1+x2)/2,-y1+0.4,0.12,(r.w/pp).toFixed(2)+'m','DIMENSIONS');
    ln(x1-0.3,-y1,x1-0.3,-y2,'DIMENSIONS');txt(x1-0.4,-(y1+y2)/2,0.12,(r.h/pp).toFixed(2)+'m','DIMENSIONS');
  });
  openings.forEach(op=>{
    const r=rooms.find(r2=>r2.id===op.roomId);if(!r)return;
    const wt2=op.width/2;let cx,cy;
    if(op.wall==='top'){cx=(r.x+r.w*op.pos)/pp;cy=r.y/pp;}
    else if(op.wall==='bottom'){cx=(r.x+r.w*op.pos)/pp;cy=(r.y+r.h)/pp;}
    else if(op.wall==='left'){cx=r.x/pp;cy=(r.y+r.h*op.pos)/pp;}
    else{cx=(r.x+r.w)/pp;cy=(r.y+r.h*op.pos)/pp;}
    ln(cx-wt2,-cy,cx+wt2,-cy,op.type==='door'?'DOORS':'WINDOWS');
    txt(cx,-(cy+0.1),0.09,(op.width*1000).toFixed(0)+'mm',op.type==='door'?'DOORS':'WINDOWS');
  });
  furniture.forEach(f=>{
    const x1=f.x/pp,y1=f.y/pp,x2=(f.x+f.w)/pp,y2=(f.y+f.h)/pp;
    poly([[x1,-y1],[x2,-y1],[x2,-y2],[x1,-y2]],'FURNITURE');
    txt((x1+x2)/2,-(y1+y2)/2,0.1,f.type.replace('Car:','').substring(0,12),'FURNITURE');
  });
  L.push('0','ENDSEC','0','EOF');
  const blob=new Blob([L.join('\\n')],{type:'text/plain'});
  const a=document.createElement('a');a.href=URL.createObjectURL(blob);a.download=(document.getElementById('tb-proj').value||'floorplan')+'.dxf';a.click();
}

