  const [disabledApps, setDisabledApps] = useState(() => {
    const DD = [];
    if (!load('appsDefaultApplied2', false)) {
      save('disabledApps', DD);
      save('appsDefaultApplied2', true);
      return DD;
    }
    return load('disabledApps', DD);
  });
  const [view, setView] = useState('grid');
  const [noteSort, setNoteSort] = useState('order'); // order | created | modified | alpha | color
  const [activeCategory, setActiveCategory] = useState('all');
  const [activeFolder, setActiveFolder] = useState(null);
  const [activeTag, setActiveTag] = useState(null);
